print(f"Wrote {len(out)} non-test entries to baseconfig_audit.json")

by_mod = defaultdict(list)
for o in out:
    by_mod[o["modality"]].append(o)
for mod in sorted(by_mod):
    print(f"\n{mod.upper()} ({len(by_mod[mod])})")
    for o in sorted(by_mod[mod], key=lambda x: x["file"] + str(x["line"]).zfill(4)):
        direct = "direct" if o["direct"] else "indirect"
        leaf = "base" if o["has_children"] else "leaf"
        tr = o["method_impl"].get("transform_request")
        trsp = o["method_impl"].get("transform_response")
        print(f"  {o['file']}:{o['line']} {o['name']} [{direct}, {leaf}, tr={tr}, trsp={trsp}]")
